const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) {
  return { json: { _unauthorized: true, error: 'internal secret required' } };
}
const leadId = body.lead_id;
const clientId = body.client_id;
const intent = body.intent || 'book_meeting';   // book_meeting | re_engage | nurture
if (!leadId || !clientId) {
  return { json: { _empty: true, error: 'lead_id and client_id required' } };
}
return { json: { _authorized: true, lead_id: leadId, client_id: clientId, intent: intent } };

// Pull all three branches and resolve persona via vertical fallback.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const leads = allOf('Fetch Lead');
const clients = allOf('Fetch Client');
const signals = allOf('Fetch Recent Signals');
const lead = leads[0] || {};
const client = clients[0] || {};
const ctx = $('Validate').item.json;

// Persona resolution: client override → vertical default → universal default.
const niche = client.niche_name || client.vertical || lead.niche_name || lead.industry || 'service_industry';
const verticalDefaults = {
  insurance:        { persona_id: 'james',  look_id: 'suit',     voice_id: 'james_voice' },
  insurance_broker: { persona_id: 'james',  look_id: 'suit',     voice_id: 'james_voice' },
  mortgage:         { persona_id: 'sarah',  look_id: 'suit',     voice_id: 'sarah_voice' },
  real_estate:      { persona_id: 'james',  look_id: 'casual',   voice_id: 'james_voice' },
  consulting:       { persona_id: 'sarah',  look_id: 'blazer',   voice_id: 'sarah_voice' },
  agencies:         { persona_id: 'sarah',  look_id: 'blazer',   voice_id: 'sarah_voice' },
  financial_advisors:{persona_id: 'james',  look_id: 'suit',     voice_id: 'james_voice' },
  legal:            { persona_id: 'james',  look_id: 'suit',     voice_id: 'james_voice' },
  construction:     { persona_id: 'marcus', look_id: 'uniform',  voice_id: 'marcus_voice' },
  contractors:      { persona_id: 'marcus', look_id: 'uniform',  voice_id: 'marcus_voice' },
  field_services:   { persona_id: 'marcus', look_id: 'polo',     voice_id: 'marcus_voice' },
  cleaning:         { persona_id: 'marcus', look_id: 'branded',  voice_id: 'marcus_voice' },
  moving:           { persona_id: 'marcus', look_id: 'branded',  voice_id: 'marcus_voice' },
  personal_services:{ persona_id: 'maria',  look_id: 'warm',     voice_id: 'maria_voice' },
  dental:           { persona_id: 'maria',  look_id: 'warm',     voice_id: 'maria_voice' },
  service_industry: { persona_id: 'james',  look_id: 'casual',   voice_id: 'james_voice' }
};
const defaults = verticalDefaults[niche] || verticalDefaults.service_industry;
const persona_id = client.preferred_persona_id || defaults.persona_id;
const look_id    = client.preferred_look_id    || defaults.look_id;
const voice_id   = client.custom_voice_id || client.preferred_voice_id || defaults.voice_id;

// Build Claude prompt for personalised 60s script.
const signalSummary = (signals || []).slice(0, 5).map(function (s) {
  return '- ' + s.signal_type + ' (' + s.signal_category + ', score ' + (s.relevance_score || 0) + ')';
}).join('\n') || '(no recent behavioral signals — generic vertical-relevant intro)';

const systemPrompt = [
  'You are writing a 60-second video sales script for ' + (client.client_name || 'a Crystallux customer') + ' — a Crystallux platform user serving the ' + niche + ' vertical.',
  '',
  'The script will be spoken by an AI persona avatar (HeyGen Avatar V) on a personalised landing page sent to one specific lead.',
  '',
  'Persona being used: ' + persona_id + ' / ' + look_id + ' (look variant). Match the tone implied by the persona:',
  '  james (B2B male, suit) — confident, professional, peer-to-peer',
  '  sarah (B2B female, blazer) — consultative, warm-but-direct',
  '  marcus (field services male, branded polo) — practical, plain-spoken',
  '  maria (personal services female, warm) — friendly, empathetic',
  '',
  'Hard limits:',
  '- 150 words MAX (a 60-second spoken script).',
  '- Open with a SPECIFIC reference to a recent signal — never generic.',
  '- One clear CTA at the end. Match intent: ' + (ctx.intent || 'book_meeting') + '.',
  '- No jargon, no hard-sell.',
  '- Output PLAIN TEXT only (no markdown, no quotes, no preamble).',
  '',
  'Lead: ' + (lead.first_name || (lead.full_name || '').split(' ')[0] || 'them') + ' at ' + (lead.company || 'their company') + ' in ' + (lead.city || 'their city') + '.',
  'Recent signals to weave in:',
  signalSummary
].join('\n');

const userPrompt = 'Write the 60-second script now. Plain text only. 150 words MAX.';

return { json: {
  lead_id: ctx.lead_id,
  client_id: ctx.client_id,
  intent: ctx.intent,
  niche_name: niche,
  persona_id: persona_id,
  look_id: look_id,
  voice_id: voice_id,
  heygen_avatar_id: client.custom_avatar_id || null,
  claude_payload: {
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 500,
    temperature: 0.7,
    system: systemPrompt,
    messages: [ { role: 'user', content: userPrompt } ]
  }
} };

const ctx = $('Build Claude Prompt').item.json;
const resp = $input.item.json || {};
let script = '';
if (resp.content && resp.content[0] && resp.content[0].text) {
  script = String(resp.content[0].text).trim();
}
if (!script) {
  script = 'Hi, this is your AI persona at ' + (ctx.client_id || 'Crystallux') + '. I noticed something relevant for you and wanted to reach out personally.';
}
return { json: {
  insert_row: {
    lead_id: ctx.lead_id,
    client_id: ctx.client_id,
    intent: ctx.intent,
    script: script,
    persona_id: ctx.persona_id,
    look_id: ctx.look_id,
    voice_id: ctx.voice_id,
    heygen_avatar_id: ctx.heygen_avatar_id,
    status: 'pending',
    content_type: 'outreach',
    retention_until: new Date(Date.now() + 90 * 24 * 60 * 60 * 1000).toISOString()
  }
} };

const inserted = $input.item.json;
const row = Array.isArray(inserted) ? inserted[0] : inserted;
if (!row || !row.id) {
  return { json: { ok: false, error: 'video_renders insert failed' } };
}
return { json: { ok: true, video_render_id: row.id, persona_id: row.persona_id, look_id: row.look_id } };
